hooks.command:
jq -r '
  .tool_input.file_path as $path |
  if ($path | startswith("docs/superpowers/specs/")) then
    {
      "hookSpecificOutput": {
        "hookEventName": "PreToolUse",
        "permissionDecision": "deny",
        "permissionDecisionReason": "⚠️ docs/superpowers/specs/ is deprecated.\n\nUse OpenSpec methodology instead:\n  /openspec-new-change  # Start new change\n  /openspec-ff-change   # Fast-forward (create all artifacts)\n  /openspec-explore     # Exploratory mode\n\nSee docs/superpowers/specs/README.md for migration details."
      }
    }
  else
    {}
  end
'
